CREATE PROCEDURE [dbo].[spProductUnitConversionCreate] @FromUnitId INT, @ToUnitId INT, @ConversionRate DECIMAL(18,6), @Description NVARCHAR(500), @CreatedByUserId INT AS BEGIN SET NOCOUNT ON; INSERT INTO [dbo].[ProductUnitConversion] (FromUnitId,ToUnitId,ConversionRate,Description,CreatedByUserId) VALUES (@FromUnitId,@ToUnitId,@ConversionRate,ISNULL(@Description,N''),NULLIF(@CreatedByUserId,0)); SELECT CAST(SCOPE_IDENTITY() AS INT); END;
